            // Windows cannot atomically rename a project from an external C: project
            // root into the plugin's D: runtime directory.
            const deletingRoot = this.projectDeletingDir;
            const stagedPath = resolveInside(deletingRoot, `${projectId}-${(0,external_node_crypto_namespaceObject.randomUUID)()}`);
            const deletionChain = this.controlledDirectoryChain();
            await this.validateStorageBoundaries(deletionChain);
            await ensureSafeDirectory(deletingRoot, "йЎ№зӣ®еҸ—жҺ§еҲ йҷӨзӣ®еҪ•");
            await this.validateStorageBoundaries(deletionChain);
            const canonicalProjectsRoot = await external_node_fs_promises_namespaceObject.realpath(this.projectsDir);
            await assertSafeDeletionEntry(this.projectsDir, canonicalProjectsRoot, projectPath, `йЎ№зӣ® ${projectId}`);
            await assertSafeDeletionRoot(deletingRoot, this.projectsDir, "йЎ№зӣ®еҸ—жҺ§еҲ йҷӨзӣ®еҪ•");
            await external_node_fs_promises_namespaceObject.rename(projectPath, stagedPath);
            try {
                const imageRequestsRoot = resolveInside(this.runtimeDir, "requests");
                const videoRequestsRoot = resolveInside(this.runtimeDir, "video-requests");
                for (const request of project.generationRequests) {
                    await this.removeControlledEntryIfPresent(imageRequestsRoot, this.runtimeDir, resolveInside(imageRequestsRoot, request.id), `еӣҫзүҮиҜ·жұӮзӣ®еҪ• ${request.id}`);
                }
                for (const request of project.videoRequests) {
                    await this.removeControlledEntryIfPresent(videoRequestsRoot, this.runtimeDir, resolveInside(videoRequestsRoot, request.id), `и§Ҷйў‘иҜ·жұӮзӣ®еҪ• ${request.id}`);
                }
                await this.removeControlledEntryIfPresent(deletingRoot, this.projectsDir, stagedPath, `еҫ…еҲ йҷӨйЎ№зӣ® ${projectId}`);
            }
