    async mergeMaskedEdit(originalPath, maskPath, generated, label) {
        const original = await external_node_fs_promises_namespaceObject.readFile(originalPath);
        const mask = await external_node_fs_promises_namespaceObject.readFile(maskPath);
        const [originalMetadata, generatedMetadata, maskMetadata] = await Promise.all([
            (0,external_sharp_namespaceObject["default"])(original, { failOn: "error" }).metadata(),
            (0,external_sharp_namespaceObject["default"])(generated, { failOn: "error" }).metadata(),
            (0,external_sharp_namespaceObject["default"])(mask, { failOn: "error" }).metadata(),
        ]);
        if (!originalMetadata.width || !originalMetadata.height)
            throw new Error(`ж— жі•иҜҶеҲ«еҺҹ${label}е°әеҜё`);
        if (!generatedMetadata.width || !generatedMetadata.height)
            throw new Error(`ж— жі•иҜҶеҲ«з”ҹжҲҗ${label}е°әеҜё`);
        const width = originalMetadata.width;
        const height = originalMetadata.height;
        if (maskMetadata.width !== width || maskMetadata.height !== height || !maskMetadata.hasAlpha) {
            throw new Error(`${label}йҖүеҢәи’ҷзүҲдёҺеҺҹеӣҫдёҚдёҖиҮҙпјҢз»“жһңе·ІжӢ’з»қеҶҷеӣһ`);
        }
        const sourceRatio = generatedMetadata.width / generatedMetadata.height;
        const targetRatio = width / height;
        if (Math.abs(Math.log(sourceRatio / targetRatio)) > 0.01) {
            throw new Error(`з”ҹжҲҗ${label}жҜ”дҫӢдёҺеҺҹеӣҫдёҚдёҖиҮҙпјҢз»“жһңе·ІжӢ’з»қеҶҷеӣһ`);
        }
        const normalizedMask = await (0,external_sharp_namespaceObject["default"])(mask, { failOn: "error" })
            .ensureAlpha()
            .png()
            .toBuffer();
        const maskedGenerated = await (0,external_sharp_namespaceObject["default"])(generated)
            .resize(width, height, { fit: "fill" })
            .ensureAlpha()
            .composite([{ input: normalizedMask, blend: "dest-in" }])
            .png()
            .toBuffer();
        return (0,external_sharp_namespaceObject["default"])(original)
            .composite([{ input: maskedGenerated, blend: "over" }])
            .png({ compressionLevel: 9 })
            .toBuffer();
    }
